<script setup lang="ts">
import { computed, ref } from "vue";
import PetRow from "../../components/PetRow.vue";
import { useCatalogStore } from "../../stores/catalog";
import { usePublishStore } from "../../stores/publish";
import { generatePublishContent, publishImagePaths } from "../../domain/publish";
const catalog=useCatalogStore();const publish=usePublishStore();const query=ref('');const account=ref('ALL');const selectedOnly=ref(false);const status=ref('');
const visible=computed(()=>catalog.pets.filter(p=>(account.value==='ALL'||p.accountId===account.value)&&(!selectedOnly.value||publish.selectedIds.includes(p.id))&&(!query.value||p.searchText.includes(query.value.toLowerCase()))));
const selected=computed(()=>publish.selectedIds.map(id=>catalog.petById.get(id)).filter(Boolean) as typeof catalog.pets);
const output=computed(()=>generatePublishContent(catalog.data,selected.value,publish.options));const images=computed(()=>publishImagePaths(catalog.data,selected.value,publish.options.allShots));
async function copy(text:string,label:string){try{await navigator.clipboard.writeText(text);status.value=`${label}已复制`;setTimeout(()=>status.value='',1800)}catch{status.value='复制失败，请手动选择文本'}}
</script>
<template><div class="page-wrap publish-page"><section class="page-intro"><div><h2>内容发布</h2><p>直接从统一宠物资产选择素材，正文与图片顺序来自同一份选择状态。</p></div><div><button class="button" @click="copy(images.join('\n'),'图片清单')">复制图片清单</button><button class="button primary" @click="copy(output,'正文')">复制正文</button></div></section><div class="publish-layout"><aside class="material-pool"><div class="section-head"><div><h2>素材池</h2><p>已选 {{selected.length}} 组 · {{images.length}} 张图</p></div><button class="link-button" @click="publish.clear">清空</button></div><div class="publish-filters"><input v-model="query" type="search" placeholder="搜索宠物、技能或定位"/><select v-model="account"><option value="ALL">全部账号</option><option v-for="item in catalog.data.accounts" :key="item.id">{{item.id}}</option></select><label><input v-model="selectedOnly" type="checkbox"/>只看已选</label></div><div class="preset-row"><button @click="publish.select(catalog.pets.map(p=>p.id))">全量资产</button><button @click="publish.select(catalog.recommendations.flatMap(g=>g.rows.map(p=>p.id)))">推荐首发</button><button @click="publish.select(visible.map(p=>p.id))">选择当前</button></div><div class="pet-list compact-list"><PetRow v-for="pet in visible" :key="pet.id" :pet="pet" selectable :checked="publish.selectedIds.includes(pet.id)" @toggle="publish.toggle"/></div></aside><main class="composer"><section class="composer-settings"><div class="section-head"><div><h2>文案设置</h2><p>生成内容始终可继续手动编辑</p></div><div class="segmented"><button :class="{active:publish.options.mode==='sale'}" @click="publish.setMode('sale')">卖号资产</button><button :class="{active:publish.options.mode==='record'}" @click="publish.setMode('record')">记录贴</button></div></div><label class="field"><span>标题</span><input v-model="publish.options.title"/></label><label class="field"><span>开场说明</span><textarea v-model="publish.options.intro" rows="3"></textarea></label><div class="option-grid"><label><input v-model="publish.options.includeStats" type="checkbox"/>面板摘要</label><label><input v-model="publish.options.includeSkills" type="checkbox"/>技能摘要</label><label><input v-model="publish.options.includeNotes" type="checkbox"/>看点一句话</label><label><input v-model="publish.options.allShots" type="checkbox"/>每组双图</label></div><div class="segmented"><button :class="{active:publish.options.format==='markdown'}" @click="publish.options.format='markdown'">Markdown</button><button :class="{active:publish.options.format==='plain'}" @click="publish.options.format='plain'">纯文本</button></div></section><section class="output-panel"><div class="section-head"><div><h2>正文预览</h2><p>{{selected.length}} 组记录，{{images.length}} 张图片</p></div><span class="copy-status">{{status}}</span></div><textarea :value="output" rows="24" spellcheck="false"></textarea></section><section class="image-order"><div class="section-head"><div><h2>图片上传顺序</h2><p>与正文中的图片引用保持一致</p></div></div><ol><li v-for="item in images" :key="item"><code>{{item}}</code><a :href="item" target="_blank">打开</a></li></ol></section></main></div></div></template>
